//! synth-bwmr — write a small fixture file in the BWMR binary format.
//!
//! Useful when you want to exercise zed-metrics-sink against a known input
//! without first running live-inference against a real .knot. The output
//! file is byte-for-byte identical to what live-inference --metrics-bin
//! would emit for the same MetricsRecord values.
//!
//! Usage:
//!   cargo run --release --example synth-bwmr -- /tmp/test-metrics.bwmr
//!   ./target/release/zed-metrics-sink --input /tmp/test-metrics.bwmr \
//!                                     --output /tmp/test-summary.jsonl

use std::env;
use std::fs::File;
use std::io::Write;

use distributed_inference::standing_wave_metrics_format::{MetricsRecord, MAGIC};

fn main() -> std::io::Result<()> {
    let path = env::args()
        .nth(1)
        .unwrap_or_else(|| "/tmp/test-metrics.bwmr".to_string());

    let recs = vec![
        MetricsRecord {
            ts: 1_714_676_400,
            token_step: 1,
            layer_idx: 0,
            hidden_dim: 4096,
            standing_count: 1248,
            coverage: 0.3047,
            speedup: 3.282,
            original_bytes: 16_384,
            compressed_bytes: 4_992,
            saved_bytes: 11_392,
            forward_ms: 47,
        },
        MetricsRecord {
            ts: 1_714_676_401,
            token_step: 1,
            layer_idx: 1,
            hidden_dim: 4096,
            standing_count: 1300,
            coverage: 0.3174,
            speedup: 3.151,
            original_bytes: 16_384,
            compressed_bytes: 5_200,
            saved_bytes: 11_184,
            forward_ms: 47,
        },
        MetricsRecord {
            ts: 1_714_676_402,
            token_step: 2,
            layer_idx: 0,
            hidden_dim: 4096,
            standing_count: 1200,
            coverage: 0.2930,
            speedup: 3.413,
            original_bytes: 16_384,
            compressed_bytes: 4_800,
            saved_bytes: 11_584,
            forward_ms: 51,
        },
    ];

    let mut f = File::create(&path)?;
    for r in &recs {
        f.write_all(&r.to_bytes())?;
    }
    f.flush()?;

    println!(
        "[synth-bwmr] wrote {} records ({} bytes) to {}; magic = {:?}",
        recs.len(),
        recs.len() * 72,
        path,
        &MAGIC
    );
    Ok(())
}
